import React, { useState, useRef } from "react";
import "bootstrap/dist/css/bootstrap.min.css";

export default function TicketVenta({ ticket, setTicket }) {
  const ticketRef = useRef(null);

  const imprimirTicket = () => {
    if (!ticketRef.current) return;
    const w = window.open("", "", "width=350,height=500");
    w.document.write(`
      <html>
        <head>
          <title>Ticket de Venta</title>
          <style>
            body { font-family: Arial, sans-serif; font-size: 14px; }
            table { width: 100%; border-collapse: collapse; margin-top: 5px; }
            th, td { text-align: left; padding: 4px; }
            th { border-bottom: 1px solid #000; }
          </style>
        </head>
        <body>
          ${ticketRef.current.innerHTML}
        </body>
      </html>
    `);
    w.document.close();
    w.print();
  };

  if (!ticket) return null;

  return (
    <div
      ref={ticketRef}
      className="card mt-4 p-3"
      style={{ width: "350px", margin: "0 auto", fontSize: "14px" }}
    >
      <h5 className="text-center fw-bold">🧾 Ticket de Venta</h5>
      <hr />

      <p><strong>Cliente:</strong> {ticket.ClienteID}</p>
      <p><strong>Emisor:</strong> {ticket.EmisorNombre}</p>
      <p><strong>Fecha:</strong> {new Date(ticket.Fecha).toLocaleString()}</p>
      <p><strong>No. Secuencia:</strong> {ticket.NumeroSecuencia}</p>

      <table className="table table-sm table-borderless mt-2 mb-2">
        <thead>
          <tr>
            <th>Producto</th>
            <th>Cant.</th>
            <th>Subtot.</th>
          </tr>
        </thead>
        <tbody>
          {ticket.productos.map((p, idx) => (
            <tr key={idx}>
              <td>{p.Nombre}</td>
              <td>{p.Cantidad}</td>
              <td>{(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <hr />
      <p className="d-flex justify-content-between">
        <span>Subtotal:</span>
        <span>{ticket.Subtotal.toFixed(2)}</span>
      </p>
      <p className="d-flex justify-content-between">
        <span>IVA:</span>
        <span>{ticket.IVA.toFixed(2)}</span>
      </p>
      <p className="d-flex justify-content-between fw-bold">
        <span>Total:</span>
        <span>{ticket.Total.toFixed(2)}</span>
      </p>

      <div className="d-flex justify-content-between mt-3">
        <button className="btn btn-primary btn-sm" onClick={imprimirTicket}>
          🖨 Imprimir
        </button>
        <button className="btn btn-secondary btn-sm" onClick={() => setTicket(null)}>
          ❌ Cerrar
        </button>
      </div>
    </div>
  );
}
